 * Integration test for SessionRepository (T044)
 *
 * TODO (T085): Fix Jest ES modules configuration
 * This test file is currently failing with ES modules import errors.
 * Complete T085 to fix Jest configuration and enable these tests.
 *
 * Demonstrates separation of concerns between T043 (ClassificationRepository)
 * and T044 (SessionRepository):
 * - T043: Write-heavy classification persistence (commands)
 * - T044: Read-heavy session analytics and lifecycle management (queries)
 *
 * This test uses a real database connection to verify:
 * 1. Session lifecycle management works end-to-end
 * 2. Performance metrics tracking is accurate
 * 3. Integration with ClassificationRepository is seamless
 * 4. Analytics queries return expected results
 */

import './setup'; // Load environment variables
import { SessionRepository } from '../../src/persistence/session-repository';
import { ClassificationRepository } from '../../src/persistence/classification-repository';
import { PrismaClient } from '@prisma/client';
import { BatchSessionConfig, EmailResult } from '../../src/types/session-types';

describe('SessionRepository Integration Test', () => {
  let sessionRepo: SessionRepository;
  let classificationRepo: ClassificationRepository;
  let prisma: PrismaClient;

  beforeAll(async () => {
    prisma = new PrismaClient();
    sessionRepo = new SessionRepository(prisma);
    classificationRepo = new ClassificationRepository(prisma);
  });

  afterAll(async () => {
    await sessionRepo.close();
    await classificationRepo.close();
  });

  describe('T043/T044 Separation of Concerns', () => {
    it('should demonstrate command-query separation with real database', async () => {
      // Setup: Create a test session using both repositories
      const config: BatchSessionConfig = {
        gmailId: `test-integration-${Date.now()}`,
        pipelineVersion: 'v1.0.0-test',
        processingMode: 'sequential',
        batchSize: 1,
        triggeredBy: 'integration-test',
      };

      // T044: Create batch session with performance tracking (Command)
      const sessionId = await sessionRepo.createBatchSession(config);
      expect(sessionId).toBeTruthy();

      // Verify session was created in database
      const session = await sessionRepo.findSessionById(sessionId);
      expect(session).not.toBeNull();
      expect(session!.gmailId).toBe(config.gmailId);
      expect(session!.pipelineVersion).toBe(config.pipelineVersion);
      expect(session!.status).toBe('in_progress');

      // T044: Update progress (Command)
      await sessionRepo.updateSessionProgress(sessionId, {
        successCount: 1,
        errorCount: 0,
      });

      // T044: Get batch progress (Query)
      const progress = await sessionRepo.getBatchProgress(sessionId);
      expect(progress.successCount).toBe(1);
      expect(progress.errorCount).toBe(0);
      expect(progress.progressPercentage).toBe(100); // 1/1 = 100%

      // T044: Complete session (Command)
      await sessionRepo.completeSession(sessionId, {
        totalDurationMs: 5000,
        avgEmailDurationMs: 5000,
        peakMemoryMb: 128.5,
      });

      // T044: Verify session is completed (Query)
      const completedSession = await sessionRepo.findSessionById(sessionId);
      expect(completedSession!.status).toBe('completed');
      expect(completedSession!.metrics).not.toBeNull();
      expect(completedSession!.metrics!.totalDurationMs).toBe(5000);

      // T044: Query performance metrics (Analytics Query)
      const metrics = await sessionRepo.getSessionPerformanceStats(sessionId);
      expect(metrics.emailCount).toBe(1);
      expect(metrics.successCount).toBe(1);
      expect(metrics.errorCount).toBe(0);
      expect(metrics.processingMode).toBe('sequential');
    }, 30000); // 30 second timeout for database operations

    it('should track errors for failed email processing', async () => {
      const config: BatchSessionConfig = {
        gmailId: `test-errors-${Date.now()}`,
        pipelineVersion: 'v1.0.0-test',
        processingMode: 'batch',
        batchSize: 2,
      };

      // Create session
      const sessionId = await sessionRepo.createBatchSession(config);

      // Record one successful and one failed email
      const successResult: EmailResult = {
        success: true,
        durationMs: 500,
      };
      await sessionRepo.recordEmailResult(sessionId, 'msg-success-001', successResult);

      const failureResult: EmailResult = {
        success: false,
        error: {
          type: 'ClassificationError',
          message: 'Failed to classify email',
          stackTrace: 'Error: Failed...',
        },
        durationMs: 100,
      };
      await sessionRepo.recordEmailResult(sessionId, 'msg-error-001', failureResult);

      // Verify error counts
      const progress = await sessionRepo.getBatchProgress(sessionId);
      expect(progress.successCount).toBe(1);
      expect(progress.errorCount).toBe(1);

      // Retrieve errors
      const errors = await sessionRepo.getSessionErrors(sessionId);
      expect(errors).toHaveLength(1);
      expect(errors[0].errorType).toBe('ClassificationError');
      expect(errors[0].emailId).toBe('msg-error-001');
    }, 30000);

    it('should query sessions by date range for analytics', async () => {
      const now = new Date();
      const startDate = new Date(now.getTime() - 60000); // 1 minute ago
