/**
 * Mock CategoryConfiguration for pipeline initialization
 * Using valid minimal config from fixtures
 */
const mockProcessingConfig = validMinimalCategoryConfig as CategoryConfiguration;

describe('test-pipeline CLI Integration Tests', () => {
  let mockFetchEmailById: jest.MockedFunction<typeof emailQuery.fetchEmailById>;
  let mockFetchUnclassifiedEmails: jest.MockedFunction<typeof emailQuery.fetchUnclassifiedEmails>;
  let mockFetchEmailsByDateRange: jest.MockedFunction<typeof emailQuery.fetchEmailsByDateRange>;
  let mockSaveClassificationResult: jest.MockedFunction<typeof classificationWriter.saveClassificationResult>;

  beforeEach(() => {
    jest.clearAllMocks();

    // Setup mocks
    mockFetchEmailById = emailQuery.fetchEmailById as jest.MockedFunction<typeof emailQuery.fetchEmailById>;
    mockFetchUnclassifiedEmails = emailQuery.fetchUnclassifiedEmails as jest.MockedFunction<
      typeof emailQuery.fetchUnclassifiedEmails
    >;
    mockFetchEmailsByDateRange = emailQuery.fetchEmailsByDateRange as jest.MockedFunction<
      typeof emailQuery.fetchEmailsByDateRange
    >;
    mockSaveClassificationResult = classificationWriter.saveClassificationResult as jest.MockedFunction<
      typeof classificationWriter.saveClassificationResult
    >;
  });

  describe('Argument Parsing and Validation', () => {
    test('should validate required mode argument', () => {
      expect(() => parseArguments([])).toThrow('Mode is required');
    });

    test('should validate mode values (single, batch, date-range)', () => {
      expect(() => parseArguments(['--mode', 'invalid'])).toThrow('Invalid mode');
    });

    test('should require message-id for single mode', () => {
      expect(() => parseArguments(['--mode', 'single'])).toThrow('message-id is required for single mode');
    });

    test('should require start and end dates for date-range mode', () => {
      expect(() => parseArguments(['--mode', 'date-range', '--start', '2025-09-01'])).toThrow(
        'Both start and end dates are required'
      );
    });

    test('should parse valid single mode arguments', () => {
      const args = parseArguments(['--mode', 'single', '--message-id', 'test-123']);

      expect(args).toEqual({
        mode: 'single',
        messageId: 'test-123',
        dryRun: false,
      });
    });

    test('should parse valid batch mode arguments with limit', () => {
      const args = parseArguments(['--mode', 'batch', '--limit', '10']);

      expect(args).toEqual({
        mode: 'batch',
        limit: 10,
        dryRun: false,
      });
    });

    test('should parse valid date-range mode arguments', () => {
      const args = parseArguments([
        '--mode',
        'date-range',
        '--start',
        '2025-09-01',
        '--end',
        '2025-09-30',
        '--limit',
        '50',
      ]);

      expect(args).toEqual({
        mode: 'date-range',
        startDate: '2025-09-01',
        endDate: '2025-09-30',
        limit: 50,
        dryRun: false,
      });
    });

    test('should recognize dry-run flag', () => {
      const args = parseArguments(['--mode', 'batch', '--dry-run']);

      expect(args.dryRun).toBe(true);
    });
  });

  describe('Single Email Processing', () => {
    test('should fetch, classify, and persist single email', async () => {
      const mockEmail = createMockEmail('msg-001', 'Team Meeting Tomorrow');

      mockFetchEmailById.mockResolvedValue(mockEmail);
      mockSaveClassificationResult.mockResolvedValue();

      const summary = await processSingleEmail('msg-001', mockProcessingConfig, false);

      expect(mockFetchEmailById).toHaveBeenCalledWith('msg-001');
      expect(mockSaveClassificationResult).toHaveBeenCalledWith('msg-001', expect.any(Object));
      expect(summary.success).toBe(1);
      expect(summary.errors).toBe(0);
    });

    test('should skip persistence in dry-run mode', async () => {
      const mockEmail = createMockEmail('msg-002', 'Test Email');

      mockFetchEmailById.mockResolvedValue(mockEmail);

      const summary = await processSingleEmail('msg-002', mockProcessingConfig, true);

      expect(mockFetchEmailById).toHaveBeenCalledWith('msg-002');
      expect(mockSaveClassificationResult).not.toHaveBeenCalled();
      expect(summary.success).toBe(1);
    });

    test('should handle email not found error', async () => {
      mockFetchEmailById.mockRejectedValue(new Error('Email with message ID "invalid-id" not found in database'));

      const summary = await processSingleEmail('invalid-id', mockProcessingConfig, false);

      expect(summary.success).toBe(0);
      expect(summary.errors).toBe(1);
      expect(summary.errorDetails).toHaveLength(1);
      expect(summary.errorDetails[0].error).toContain('not found');
    });

    test('should handle classification errors', async () => {
      const mockEmail = createMockEmail('msg-003', 'Test Email');

      mockFetchEmailById.mockResolvedValue(mockEmail);

      // Mock ClassificationPipeline to throw error
      jest.spyOn(ClassificationPipeline.prototype, 'classify').mockRejectedValue(new Error('Classification failed'));

      const summary = await processSingleEmail('msg-003', mockProcessingConfig, false);

      expect(summary.success).toBe(0);
      expect(summary.errors).toBe(1);
    });
  });

  describe('Batch Email Processing', () => {
    test('should fetch, classify, and persist multiple emails', async () => {
      const mockEmails = [
        createMockEmail('msg-001', 'Email 1'),
        createMockEmail('msg-002', 'Email 2'),
        createMockEmail('msg-003', 'Email 3'),
      ];

      mockFetchUnclassifiedEmails.mockResolvedValue(mockEmails);
      mockSaveClassificationResult.mockResolvedValue();

      const summary = await processBatchEmails(10, mockProcessingConfig, false);

      expect(mockFetchUnclassifiedEmails).toHaveBeenCalledWith(10);
      expect(mockSaveClassificationResult).toHaveBeenCalledTimes(3);
      expect(summary.success).toBe(3);
      expect(summary.errors).toBe(0);
    });

    test('should continue processing batch on individual errors', async () => {
      const mockEmails = [
        createMockEmail('msg-001', 'Email 1'),
        createMockEmail('msg-002', 'Email 2'),
        createMockEmail('msg-003', 'Email 3'),
      ];

      mockFetchUnclassifiedEmails.mockResolvedValue(mockEmails);
      mockSaveClassificationResult.mockResolvedValueOnce(); // First succeeds
      mockSaveClassificationResult.mockRejectedValueOnce(new Error('Database error')); // Second fails
      mockSaveClassificationResult.mockResolvedValueOnce(); // Third succeeds

      const summary = await processBatchEmails(10, mockProcessingConfig, false);

      expect(summary.success).toBe(2);
      expect(summary.errors).toBe(1);
      expect(summary.errorDetails).toHaveLength(1);
    });

    test('should handle empty batch gracefully', async () => {
      mockFetchUnclassifiedEmails.mockResolvedValue([]);

      const summary = await processBatchEmails(10, mockProcessingConfig, false);

      expect(summary.success).toBe(0);
      expect(summary.errors).toBe(0);
      expect(summary.totalEmails).toBe(0);
    });
  });

  describe('Date Range Processing', () => {
    test('should fetch, classify, and persist emails by date range', async () => {
      const mockEmails = [createMockEmail('msg-001', 'Email 1'), createMockEmail('msg-002', 'Email 2')];

      mockFetchEmailsByDateRange.mockResolvedValue(mockEmails);
      mockSaveClassificationResult.mockResolvedValue();

      const summary = await processDateRangeEmails('2025-09-01', '2025-09-30', 50, mockProcessingConfig, false);

      expect(mockFetchEmailsByDateRange).toHaveBeenCalledWith(new Date('2025-09-01'), new Date('2025-09-30'), 50);
      expect(mockSaveClassificationResult).toHaveBeenCalledTimes(2);
      expect(summary.success).toBe(2);
    });

    test('should validate date range order', async () => {
      await expect(processDateRangeEmails('2025-09-30', '2025-09-01', 50, mockProcessingConfig, false)).rejects.toThrow(
        'Invalid date range'
      );
    });
  });

  describe('Output Formatting', () => {
    test('should format per-email output correctly', async () => {
      const mockEmail = createMockEmail('msg-001', 'Team Meeting Tomorrow');

      const mockResult = createMockClassificationResult();
      const output = formatEmailOutput(mockEmail, mockResult);

      expect(output).toContain('[msg-001]');
      expect(output).toContain('Team Meeting Tomorrow');
      expect(output).toContain('WORK.MEETING');
      expect(output).toContain('0.85');
      expect(output).toContain('8.3s');
    });

    test('should format summary statistics correctly', async () => {
      const summary = {
        totalEmails: 10,
        success: 9,
        errors: 1,
        totalDurationMs: 83500,
        errorDetails: [{ messageId: 'msg-005', error: 'Classification failed' }],
      };

      const output = formatSummary(summary);

      expect(output).toContain('Processed 10 emails');
      expect(output).toContain('83.5s');
      expect(output).toContain('avg 8.35s/email');
      expect(output).toContain('9 success');
      expect(output).toContain('1 error');
    });
  });

  describe('Explainability Trace Output', () => {
    test('should write explainability traces to timestamped directory', async () => {
      const mockEmail = createMockEmail('msg-001', 'Test Email');
      const mockResult = createMockClassificationResult();

      const outputPath = await writeExplainabilityTrace(mockEmail, 'test-session-123', mockResult);

      expect(outputPath).toMatch(/test-pipeline-results\/\d{8}-\d{6}\/msg-001\.json/);
    });
  });

  describe('End-to-End Integration', () => {
    test('should run complete pipeline flow successfully', async () => {
      const mockEmail = createMockEmail('msg-001', 'Team Meeting Tomorrow');

      mockFetchEmailById.mockResolvedValue(mockEmail);
      mockSaveClassificationResult.mockResolvedValue();

      const exitCode = await runTestPipeline(['--mode', 'single', '--message-id', 'msg-001']);

      expect(exitCode).toBe(0);
      expect(mockFetchEmailById).toHaveBeenCalled();
      expect(mockSaveClassificationResult).toHaveBeenCalled();
    });

    test('should return non-zero exit code on errors', async () => {
      mockFetchEmailById.mockRejectedValue(new Error('Database connection failed'));

      const exitCode = await runTestPipeline(['--mode', 'single', '--message-id', 'msg-001']);

      expect(exitCode).toBe(1);
    });
  });
});

